//! foil-entropy-boost — Rust sidecar generating structured entropy via
//! garden/fission for FOIL cache-key teleportation.
//!
//! Each agent runs an entropy garden with timing jitter mixed in (genuine
//! entropy from OS scheduler noise). Gardens restart on convergence to
//! keep entropy flowing. Shape keys feed FOIL cache speculation.
//!
//! Cost: ~0.003% CPU per agent at gnosis time (5s breath).
//! Gain: FOIL cache hits avoid full inference.
//!
//! Lean: NoiseIsUnresolvedSignal, GodFormula, DigitalHadronCollider,
//!       LandauerPrincipleAsClinaemenDebt, SpectralMeasurementFramework.
//!
//! —Claude

use std::env;
use std::sync::atomic::{AtomicU64, Ordering};
use std::sync::mpsc;
use std::thread;
use std::time::{Duration, Instant};

use distributed_inference::gnosis_foil::{
    foil_entropy_boost_admit, foil_entropy_boost_admit_predicted, foil_entropy_boost_telemetry,
    foil_entropy_observe_cost, foil_entropy_predicted_telemetry, foil_entropy_reynolds_telemetry,
    ENTROPY_REYNOLDS_NUMBER_NS,
};
use distributed_inference::noise_is_unresolved_signal::{CellState, EntropyGarden};

static TOTAL_BREATHS: AtomicU64 = AtomicU64::new(0);
static TOTAL_WINDOWS: AtomicU64 = AtomicU64::new(0);
static TOTAL_ENTROPY_BYTES: AtomicU64 = AtomicU64::new(0);
static TOTAL_KEYS_GENERATED: AtomicU64 = AtomicU64::new(0);
static TOTAL_RESTARTS: AtomicU64 = AtomicU64::new(0);
static TOTAL_HEAT: AtomicU64 = AtomicU64::new(0);
static TOTAL_DETONATIONS: AtomicU64 = AtomicU64::new(0);
static TOTAL_FRAGMENTS: AtomicU64 = AtomicU64::new(0);
static TOTAL_PREDICTED_KEYS: AtomicU64 = AtomicU64::new(0);
static TOTAL_PREDICTED_ADMITTED: AtomicU64 = AtomicU64::new(0);

struct EntropyHarvest {
    agent_id: usize,
    window: u32,
    shell: u8,
    entropy_bytes: Vec<u8>,
    foil_key: u64,
    shape_key: String,
    standing: u32,
    void_count: u32,
    heat: u32,
    jitter_ns: u64,
}

fn fold_to_key(bytes: &[u8]) -> u64 {
    let mut h: u64 = 0xcbf29ce484222325;
    for &b in bytes {
        h ^= b as u64;
        h = h.wrapping_mul(0x100000001b3);
    }
    h
}

fn harvest(garden: &EntropyGarden, agent_id: usize, jitter_ns: u64) -> EntropyHarvest {
    let census = garden.census();
    let mut entropy_bytes: Vec<u8> = Vec::new();
    let mut heat = 0u32;

    for cell in &garden.cells {
        match cell.state {
            CellState::Void => {
                // White noise: genuine entropy
                let last = cell.observations[2];
                entropy_bytes.push((last * 255.0) as u8);
                // Mix jitter
                entropy_bytes.push((jitter_ns & 0xff) as u8);
            }
            CellState::Pink | CellState::Brown => {
                let bit = if cell.variance > 0.005 { 1u8 } else { 0u8 };
                entropy_bytes.push(bit);
            }
            _ => {}
        }
        if cell.variance > 0.1 && cell.state == CellState::Void {
            heat += 1;
        }
    }

    // Mix agent_id + timestamp into entropy for uniqueness
    let ts = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default()
        .as_nanos() as u64;
    entropy_bytes.extend_from_slice(&ts.to_le_bytes());
    entropy_bytes.extend_from_slice(&(agent_id as u64).to_le_bytes());

    let foil_key = fold_to_key(&entropy_bytes);
    let shape_key = format!(
        "rf-entropy:{:016x}:agent={}:shell={}:sw={}:void={}:jitter={}",
        foil_key,
        agent_id,
        garden.shell,
        census.standing_count,
        census.void_count,
        jitter_ns % 10000
    );

    EntropyHarvest {
        agent_id,
        window: garden.windows_completed,
        shell: garden.shell,
        entropy_bytes,
        foil_key,
        shape_key,
        standing: census.standing_count,
        void_count: census.void_count,
        heat,
        jitter_ns,
    }
}

fn run_agent(
    agent_id: usize,
    width: u32,
    height: u32,
    breath_ms: u64,
    report_every: u32,
    tx: mpsc::Sender<EntropyHarvest>,
) {
    let breath_dur = Duration::from_millis(breath_ms);
    let mut generation = 0u64;

    loop {
        // Create a new garden with unique seed per agent + generation
        let seed = (agent_id as u64)
            .wrapping_mul(0x9e3779b97f4a7c15)
            .wrapping_add(generation.wrapping_mul(0x517cc1b727220a95));
        let mut garden = EntropyGarden::new_seeded(width, height, seed);
        generation += 1;
        TOTAL_RESTARTS.fetch_add(1, Ordering::Relaxed);

        println!(
            "[agent-{}] gen {} started (seed {:016x})",
            agent_id, generation, seed
        );

        loop {
            // Measure timing jitter: how far off was our sleep from expected?
            let expected_wake = Instant::now() + breath_dur;
            thread::sleep(breath_dur);
            let actual_wake = Instant::now();
            let jitter_ns = actual_wake
                .checked_duration_since(expected_wake)
                .unwrap_or_default()
                .as_nanos() as u64;

            TOTAL_BREATHS.fetch_add(1, Ordering::Relaxed);

            // Boost mode: detonate + breathe + classify in correct order.
            // Fission products scatter BEFORE DFT classification.
            let slot = agent_id as u32;
            let total_slots = 4;
            let (window_result, det) = garden.breathe_boost(jitter_ns, slot, total_slots);

            if let Some(ref d) = det {
                if d.triggered {
                    TOTAL_DETONATIONS.fetch_add(1, Ordering::Relaxed);
                    TOTAL_FRAGMENTS.fetch_add(d.fragment_count as u64, Ordering::Relaxed);
                    TOTAL_HEAT.fetch_add(d.heat as u64, Ordering::Relaxed);
                }
            }

            if let Some(result) = window_result {
                TOTAL_WINDOWS.fetch_add(1, Ordering::Relaxed);

                let h = harvest(&garden, agent_id, jitter_ns);
                TOTAL_ENTROPY_BYTES.fetch_add(h.entropy_bytes.len() as u64, Ordering::Relaxed);
                TOTAL_KEYS_GENERATED.fetch_add(1, Ordering::Relaxed);
                TOTAL_HEAT.fetch_add(h.heat as u64, Ordering::Relaxed);

                if garden.windows_completed.is_multiple_of(report_every) {
                    println!(
                        "[agent-{}] w{} sh{} | {}B entropy {}sw {}void {}heat jitter={}ns | {}",
                        agent_id,
                        h.window,
                        h.shell,
                        h.entropy_bytes.len(),
                        h.standing,
                        h.void_count,
                        h.heat,
                        h.jitter_ns,
                        &h.shape_key[..60.min(h.shape_key.len())]
                    );
                }

                // Feed computation cost to Reynolds gate (breath duration = proxy for workload)
                // Real workloads feed actual inference latency here
                foil_entropy_observe_cost(jitter_ns.max(10_000));

                // First-class FOIL admission (Reynolds-gated: zero cost below crossover)
                let admitted = foil_entropy_boost_admit(h.foil_key, &h.entropy_bytes, h.jitter_ns);
                if !admitted {
                    // Queue full — sidecar producing faster than FOIL consumes
                    // This is fine; entropy is renewable
                }

                // DFT-predicted key admission: standing wave frequencies predict
                // recurring query patterns. Higher hit rate than random keys.
                let predicted_keys = garden.predict_next_keys();
                if !predicted_keys.is_empty() {
                    let pk_count = predicted_keys.len() as u64;
                    TOTAL_PREDICTED_KEYS.fetch_add(pk_count, Ordering::Relaxed);
                    let pk_admitted = foil_entropy_boost_admit_predicted(
                        &predicted_keys,
                        garden.shell,
                        h.jitter_ns,
                    );
                    TOTAL_PREDICTED_ADMITTED.fetch_add(pk_admitted as u64, Ordering::Relaxed);
                }

                let void_count = h.void_count;
                let standing = h.standing;
                let _ = tx.send(h);

                // Restart garden when entropy dries up (all resolved)
                if void_count == 0
                    && standing + result.resolved_count >= (width * height) / 2
                {
                    println!(
                        "[agent-{}] garden converged at w{} sh{}, restarting",
                        agent_id, garden.windows_completed, garden.shell
                    );
                    break;
                }
            }
        }
    }
}

fn main() {
    let args: Vec<String> = env::args().collect();
    let get = |flag: &str| -> Option<String> {
        args.iter()
            .position(|a| a == flag)
            .and_then(|p| args.get(p + 1))
            .cloned()
    };

    let agents: usize = get("--agents").and_then(|s| s.parse().ok()).unwrap_or(4);
    let breath_ms: u64 = get("--breath-ms")
        .and_then(|s| s.parse().ok())
        .unwrap_or(5000);
    let gw: u32 = get("--garden-width")
        .and_then(|s| s.parse().ok())
        .unwrap_or(16);
    let gh: u32 = get("--garden-height")
        .and_then(|s| s.parse().ok())
        .unwrap_or(16);
    let report: u32 = get("--report-interval")
        .and_then(|s| s.parse().ok())
        .unwrap_or(3);

    println!("=== FOIL ENTROPY BOOST SIDECAR ===");
    println!("  Agents: {}", agents);
    println!(
        "  Garden: {}x{} ({} cells/agent, {} total)",
        gw,
        gh,
        gw * gh,
        gw * gh * agents as u32
    );
    println!("  Breath: {}ms", breath_ms);
    println!("  Unique seeds per agent + generation (timing jitter mixed)");
    println!("  Auto-restart on convergence (continuous entropy flow)");
    println!();

    let (tx, rx) = mpsc::channel::<EntropyHarvest>();

    // Collector thread
    let collector = thread::spawn(move || {
        let mut total = 0u64;
        let mut bytes = 0u64;
        let mut keys = std::collections::HashSet::new();
        let mut active_agents = std::collections::HashSet::new();
        let start = Instant::now();

        for h in rx {
            total += 1;
            bytes += h.entropy_bytes.len() as u64;
            keys.insert(h.foil_key);
            active_agents.insert(h.agent_id);

            if total.is_multiple_of(agents as u64 * 5) {
                let elapsed = start.elapsed().as_secs_f64();
                println!();
                println!("--- AGGREGATE ({:.0}s) ---", elapsed);
                println!("  Harvests: {} ({:.1}/s)", total, total as f64 / elapsed);
                println!(
                    "  Entropy: {} bytes ({:.0} bits/s)",
                    bytes,
                    bytes as f64 * 8.0 / elapsed
                );
                println!("  Unique FOIL keys: {}", keys.len());
                println!("  Active agents: {}/{}", active_agents.len(), agents);
                println!("  Restarts: {}", TOTAL_RESTARTS.load(Ordering::Relaxed));
                println!(
                    "  Detonations: {}",
                    TOTAL_DETONATIONS.load(Ordering::Relaxed)
                );
                println!("  Fragments: {}", TOTAL_FRAGMENTS.load(Ordering::Relaxed));
                println!("  Heat: {} Bules", TOTAL_HEAT.load(Ordering::Relaxed));
                let (boost_admitted, boost_dropped, jitter_pool) = foil_entropy_boost_telemetry();
                let (ema_ns, gate_active, gate_suppressed) = foil_entropy_reynolds_telemetry();
                let (pred_admitted, pred_dropped, pred_hits, rand_hits) =
                    foil_entropy_predicted_telemetry();
                println!(
                    "  FOIL random admitted: {} | dropped: {} | jitter pool: {}ns",
                    boost_admitted, boost_dropped, jitter_pool
                );
                println!(
                    "  FOIL predicted: generated={} admitted={} (local: keys={} admitted={})",
                    TOTAL_PREDICTED_KEYS.load(Ordering::Relaxed),
                    pred_admitted,
                    TOTAL_PREDICTED_KEYS.load(Ordering::Relaxed),
                    TOTAL_PREDICTED_ADMITTED.load(Ordering::Relaxed)
                );
                println!("  FOIL predicted dropped: {}", pred_dropped);
                println!(
                    "  Hit tracking: predicted_hits={} random_hits={}",
                    pred_hits, rand_hits
                );
                if pred_hits + rand_hits > 0 {
                    let pred_rate = if pred_admitted > 0 {
                        pred_hits as f64 / pred_admitted as f64 * 100.0
                    } else {
                        0.0
                    };
                    let rand_rate = if boost_admitted > 0 {
                        rand_hits as f64 / boost_admitted as f64 * 100.0
                    } else {
                        0.0
                    };
                    println!(
                        "  Hit rates: predicted={:.1}% random={:.1}%",
                        pred_rate, rand_rate
                    );
                }
                println!(
                    "  Reynolds gate: EMA={}ns (threshold={}ns) | active={} suppressed={}",
                    ema_ns, ENTROPY_REYNOLDS_NUMBER_NS, gate_active, gate_suppressed
                );
                println!();
            }
        }
    });

    // Spawn agents
    let mut handles = Vec::new();
    for i in 0..agents {
        let tx = tx.clone();
        let handle = thread::spawn(move || run_agent(i, gw, gh, breath_ms, report, tx));
        handles.push(handle);
    }
    drop(tx);

    for h in handles {
        let _ = h.join();
    }
    let _ = collector.join();
}
